"""
Agent RL Demo: rllm + TRL integration on Mac Air

Usage:
    # Natural language:
    python -m rllm_train.train "用 qwen-0.5b 训练数学 agent，64 个问题，2 个 epoch"
    python -m rllm_train.train "quick test with 16 problems"

    # Default config:
    python -m rllm_train.train
"""

import os
import re
import sys
import warnings

os.environ["TRL_EXPERIMENTAL_SILENCE"] = "1"
os.environ["TOKENIZERS_PARALLELISM"] = "false"
os.environ["HF_HUB_DISABLE_PROGRESS_BARS"] = "1"
os.environ["HF_HUB_DISABLE_IMPLICIT_TOKEN"] = "1"
os.environ["TRANSFORMERS_NO_ADVISORY_WARNINGS"] = "1"

warnings.filterwarnings("ignore", message=".*pin_memory.*")
warnings.filterwarnings("ignore", message=".*torch_dtype.*is deprecated.*")
warnings.filterwarnings("ignore", message=".*attention mask is not set.*")
warnings.filterwarnings("ignore", message=".*unauthenticated requests.*")

import logging
logging.getLogger("huggingface_hub").setLevel(logging.ERROR)

import torch
from datasets import Dataset
import transformers
transformers.logging.set_verbosity_error()
from transformers import AutoModelForCausalLM, AutoTokenizer, TrainerCallback, PrinterCallback
from trl import GRPOConfig, GRPOTrainer

from rllm_train.base import ToolOutput
from rllm_train.config import TrainingConfig, parse_natural_language
from rllm_train.logger import TrainingLogger
from rllm_train.math_env import MathCalcEnv, generate_math_problems
from rllm_train.perf_stats import PerfTracker
from rllm_train.rollout import make_rllm_rollout_func
from rllm_train.tool_agent import ToolAgent
from rllm_train.trajectory_writer import TrajectoryWriter


def build_dataset(problems):
    records = []
    for p in problems:
        records.append({
            "prompt": [{"role": "user", "content": p["question"]}],
            "answer": p["answer"],
        })
    return Dataset.from_list(records)


TOOL_SYSTEM_PROMPT = """You are a helpful math assistant. You can use the calculate tool to compute arithmetic expressions, and the finish tool to give your final answer.

Always use the calculate tool first, then use finish to report the result."""


class CalculateTool:
    name = "calculate"
    description = "Evaluate a mathematical expression"
    parameters = {
        "type": "object",
        "properties": {
            "expression": {
                "type": "string",
                "description": "The math expression to evaluate, e.g. '2 + 3'"
            }
        },
        "required": ["expression"]
    }

    def __init__(self, **kwargs):
        pass

    def __call__(self, expression: str = "", **kwargs) -> ToolOutput:
        try:
            allowed = set("0123456789+-*/.() ")
            if not all(c in allowed for c in str(expression)):
                return ToolOutput(output="Error: invalid expression")
            result = eval(str(expression))  # noqa: S307
            return ToolOutput(output=str(result))
        except Exception as e:
            return ToolOutput(output=f"Error: {e}")

    @property
    def json(self):
        return {
            "type": "function",
            "function": {
                "name": self.name,
                "description": self.description,
                "parameters": self.parameters,
            }
        }


class FinishTool:
    name = "finish"
    description = "Submit your final answer"
    parameters = {
        "type": "object",
        "properties": {
            "response": {
                "type": "string",
                "description": "Your final answer"
            }
        },
        "required": ["response"]
    }

    def __init__(self, **kwargs):
        pass

    def __call__(self, response: str = "", **kwargs) -> ToolOutput:
        return ToolOutput(output=response)

    @property
    def json(self):
        return {
            "type": "function",
            "function": {
                "name": self.name,
                "description": self.description,
                "parameters": self.parameters,
            }
        }


def create_simple_tool_agent():
    return {
        "system_prompt": TOOL_SYSTEM_PROMPT,
        "parser_name": "qwen",
        "tool_map": {
            "calculate": CalculateTool,
            "finish": FinishTool,
        },
    }


class RllmCallback(TrainerCallback):
    def __init__(self, training_logger):
        self.training_logger = training_logger
        self._steps_synced = False

    def on_step_begin(self, args, state, control, **kwargs):
        if not self._steps_synced and state.max_steps > 0:
            self.training_logger.total_steps = state.max_steps
            self._steps_synced = True

    def on_log(self, args, state, control, logs=None, **kwargs):
        if logs:
            self.training_logger.update_training_metrics(logs)


def math_reward_fn(prompts, completions, **kwargs):
    rewards = []
    answers = kwargs.get("answer", [])
    for i, (prompt, completion) in enumerate(zip(prompts, completions)):
        gt = answers[i] if i < len(answers) else None
        if isinstance(completion, list):
            text = " ".join(
                msg.get("content", "") for msg in completion if isinstance(msg, dict)
            )
        else:
            text = str(completion)
        numbers = re.findall(r'-?\d+\.?\d*', text)
        if numbers and gt is not None:
            try:
                predicted = float(numbers[-1])
                expected = float(gt)
                rewards.append(1.0 if abs(predicted - expected) < 1e-6 else 0.0)
            except (ValueError, TypeError):
                rewards.append(0.0)
        else:
            rewards.append(0.0)
    return rewards


def main(config: TrainingConfig | None = None):
    if config is None:
        config = TrainingConfig()

    output_dir = config.output_dir
    os.makedirs(output_dir, exist_ok=True)

    config.to_json(os.path.join(output_dir, "config.json"))

    log_file = os.path.join(output_dir, "training_log.txt")
    log = TrainingLogger(verbose=config.verbose, log_file=log_file)
    log.log_training_start(config)

    tokenizer = AutoTokenizer.from_pretrained(config.model_name, trust_remote_code=True)
    if tokenizer.pad_token is None:
        tokenizer.pad_token = tokenizer.eos_token

    if torch.cuda.is_available():
        device = "cuda"
        dtype = torch.bfloat16
    elif torch.backends.mps.is_available():
        device = "mps"
        dtype = torch.float32
    else:
        device = "cpu"
        dtype = torch.float32

    model = AutoModelForCausalLM.from_pretrained(
        config.model_name, torch_dtype=dtype, trust_remote_code=True,
    )
    param_count = sum(p.numel() for p in model.parameters())
    log.log_model_loaded(config.model_name, device, param_count)

    problems = generate_math_problems(n=config.num_problems, seed=config.seed, difficulty=config.difficulty)
    dataset = build_dataset(problems)
    log.log_dataset_ready(len(dataset), dataset[0])

    traj_writer = TrajectoryWriter(output_dir, enabled=True)
    perf = PerfTracker(output_dir, enabled=True)

    agent_args = create_simple_tool_agent()

    answer_map = {p["question"]: p["answer"] for p in problems}

    rollout_func = make_rllm_rollout_func(
        agent_class=ToolAgent,
        agent_args=agent_args,
        env_class=MathCalcEnv,
        env_args={"max_steps": config.max_agent_steps},
        max_steps=config.max_agent_steps,
        max_response_length=config.max_response_length,
        max_prompt_length=config.max_prompt_length,
        sampling_params={"temperature": config.temperature, "top_p": config.top_p},
        training_logger=log,
        trajectory_writer=traj_writer,
        perf_tracker=perf,
        answer_map=answer_map,
    )

    training_args = GRPOConfig(
        output_dir=output_dir,
        num_train_epochs=config.num_epochs,
        per_device_train_batch_size=config.batch_size,
        num_generations=config.num_generations,
        max_completion_length=config.max_completion_length,
        learning_rate=config.learning_rate,
        logging_steps=config.logging_steps,
        logging_strategy="steps",
        log_level="error",
        save_strategy="no",
        bf16=(dtype == torch.bfloat16),
        fp16=False,
        gradient_accumulation_steps=config.gradient_accumulation_steps,
        gradient_checkpointing=True,
        report_to="none",
        remove_unused_columns=False,
        disable_tqdm=True,
    )

    log.log_trainer_ready(config.num_epochs)

    perf.start_training()

    logging.getLogger("trl").setLevel(logging.ERROR)

    trainer = GRPOTrainer(
        model=model,
        args=training_args,
        processing_class=tokenizer,
        train_dataset=dataset,
        reward_funcs=[math_reward_fn],
        rollout_func=rollout_func,
        callbacks=[RllmCallback(log)],
    )

    trainer.remove_callback(PrinterCallback)

    trainer.train()

    # Sync perf stats into logger for the report
    log.set_perf_stats(perf.rollout_stats)
    perf.save_to_file()

    perf_summary = perf.get_summary()
    log.print_training_report(config, perf_summary, output_dir)

    if config.save_model:
        save_path = os.path.join(output_dir, "final_model")
        model.save_pretrained(save_path)
        tokenizer.save_pretrained(save_path)
        log.log_model_saved(save_path)

    log.close()


if __name__ == "__main__":
    if len(sys.argv) > 1:
        arg = " ".join(sys.argv[1:])
        if arg.endswith(".json") and os.path.isfile(arg):
            cfg = TrainingConfig.from_json(arg)
        else:
            cfg = parse_natural_language(arg)
    else:
        cfg = TrainingConfig()
    main(cfg)

import asyncio
import logging
import time

import torch

from rllm_train.hf_engine import HFAgentExecutionEngine
from rllm_train.math_env import MathCalcEnv

logger = logging.getLogger(__name__)


def make_rllm_rollout_func(
    agent_class,
    agent_args=None,
    env_class=None,
    env_args=None,
    max_steps=3,
    max_response_length=256,
    max_prompt_length=512,
    sampling_params=None,
    training_logger=None,
    trajectory_writer=None,
    perf_tracker=None,
    answer_map=None,
):
    if agent_args is None:
        agent_args = {}
    if env_args is None:
        env_args = {}
    if env_class is None:
        env_class = MathCalcEnv
    if sampling_params is None:
        sampling_params = {"temperature": 0.7, "top_p": 0.9}
    if answer_map is None:
        answer_map = {}

    _step_counter = [0]

    def rollout_func(prompts, trainer):
        _step_counter[0] += 1
        step = _step_counter[0]
        model = trainer.model
        tokenizer = trainer.processing_class
        device = trainer.accelerator.device

        num_gens = getattr(trainer.args, "num_generations", len(prompts))
        if training_logger:
            training_logger.log_rollout_start(step, len(prompts), num_gens)
        if perf_tracker:
            perf_tracker.start_rollout(step)

        model.eval()

        engine = HFAgentExecutionEngine(
            model=model,
            tokenizer=tokenizer,
            n_parallel_agents=len(prompts),
            max_steps=max_steps,
            max_response_length=max_response_length,
            max_prompt_length=max_prompt_length,
            agent_class=agent_class,
            agent_args=agent_args,
            env_class=env_class,
            env_args=env_args,
            sampling_params=sampling_params,
            on_trajectory_done=lambda idx, total, reward: (
                training_logger.log_trajectory_done(step, idx, total, reward)
                if training_logger else None
            ),
        )

        envs = []
        agents = []
        for prompt in prompts:
            task = _extract_task_from_prompt(prompt)
            if task["question"] in answer_map:
                task["answer"] = answer_map[task["question"]]
            task.update(env_args)
            env = env_class.from_dict(task)
            agent = agent_class(**agent_args)
            envs.append(env)
            agents.append(agent)

        engine.update_envs_and_agents(envs, agents)

        try:
            loop = asyncio.get_event_loop()
            if loop.is_running():
                import concurrent.futures
                with concurrent.futures.ThreadPoolExecutor() as pool:
                    results = pool.submit(
                        lambda: asyncio.run(engine.run_trajectories(mode="Token"))
                    ).result()
            else:
                results = loop.run_until_complete(engine.run_trajectories(mode="Token"))
        except RuntimeError:
            results = asyncio.run(engine.run_trajectories(mode="Token"))

        model.train()

        # Perf tracking: end rollout phase
        rollout_stats = None
        if perf_tracker:
            rollout_stats = perf_tracker.end_rollout(results)

        # Write trajectories to file
        if trajectory_writer:
            trajectory_writer.write_rollout(step, agents, envs, results, tokenizer)

        prompt_ids_list = []
        completion_ids_list = []
        env_mask_list = []

        for result in results:
            prompt_ids_list.append(result["prompt_tokens"].tolist())
            completion_ids_list.append(result["response_tokens"].tolist())
            env_mask_list.append(result["response_masks"].tolist())

        rewards = [r.get("trajectory_reward", 0.0) if isinstance(r, dict) else 0.0 for r in results]
        if training_logger:
            training_logger.log_rollout_done(step, len(results), rewards, rollout_stats=rollout_stats)

        # Compute logprobs with timing
        if training_logger:
            training_logger.log_logprob_start(step)
        if perf_tracker:
            perf_tracker.start_logprob_compute()

        logprobs_list = _compute_logprobs(
            model, tokenizer, prompt_ids_list, completion_ids_list, device
        )

        if perf_tracker:
            perf_tracker.end_logprob_compute()

        if training_logger:
            training_logger.log_training_update_start(step)

        return {
            "prompt_ids": prompt_ids_list,
            "completion_ids": completion_ids_list,
            "logprobs": logprobs_list,
            "env_mask": env_mask_list,
        }

    return rollout_func


def _extract_task_from_prompt(prompt):
    if isinstance(prompt, list):
        for msg in prompt:
            if isinstance(msg, dict) and msg.get("role") == "user":
                return {"question": msg["content"]}
        return {"question": str(prompt)}
    return {"question": str(prompt)}


def _compute_logprobs(model, tokenizer, prompt_ids_list, completion_ids_list, device):
    logprobs_list = []
    for prompt_ids, completion_ids in zip(prompt_ids_list, completion_ids_list):
        if not completion_ids:
            logprobs_list.append([])
            continue
        input_ids = torch.tensor([prompt_ids + completion_ids], device=device)
        with torch.no_grad():
            outputs = model(input_ids)
            logits = outputs.logits
        prompt_len = len(prompt_ids)
        completion_logits = logits[0, prompt_len - 1:-1, :]
        completion_tokens = torch.tensor(completion_ids, device=device)
        log_probs = torch.log_softmax(completion_logits, dim=-1)
        token_logprobs = log_probs.gather(1, completion_tokens.unsqueeze(1)).squeeze(1)
        logprobs_list.append(token_logprobs.cpu().tolist())
    return logprobs_list

